document.addEventListener("DOMContentLoaded", function () { const e = window.egro_security?.token || "", t = window.egro_security?.nonce || ""; if (!e) return void console.error("Токен безопасности ArtCly SMTP не доступен"); document.querySelectorAll("form").forEach(n => { n.querySelector('input[type="hidden"][name="action"][value="mail_to"]'); const c = n.querySelector('input[name="egro_security_token"]'), o = n.querySelector('input[name="egro_form_nonce"]'), r = n.querySelector('input[name="egro_website"]'); if (!c) { const t = document.createElement("input"); t.type = "hidden", t.name = "egro_security_token", t.value = e, n.appendChild(t) } if (!o && t) { const e = document.createElement("input"); e.type = "hidden", e.name = "egro_form_nonce", e.value = t, n.appendChild(e) } if (!r) { const e = document.createElement("input"); e.type = "text", e.name = "egro_website", e.value = "", e.style.display = "none", n.appendChild(e) } }) });